use std::fs::File;
use std::io::{self, Write, Read};

struct ConfigRecord {
    key: [u8; 64],
    value_len: u32,
    value: Vec<u8>,
}

fn main() -> io::Result<()> {
    let file_path = "test_config.bin";
    File::create(file_path)?;

    let initial_data: Vec<u8> = b"initial setup data".to_vec();
    {
        let mut file = File::options().write(true).open(file_path)?;
        file.write(&initial_data)?; 
    }

    let metadata = std::fs::metadata(file_path)?.len();
    println!("File size created: {} bytes.", metadata);

    let mut file = File::open(file_path)?;
    let mut buffer = vec![0u8; metadata as usize];
    file.read_exact(&mut buffer)?; 

    println!("Successfully read initial block of data.");

    let record_count = 1;
    println!("Simulated processing {} records safely.", record_count);

    Ok(())
}
